import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"平台功能: 核心命令与技能管理 | OpenSkills","description":"学习 OpenSkills 平台功能，掌握命令、安装、列出、更新和删除技能等核心操作，理解全局与项目管理的差异。","frontmatter":{"title":"平台功能: 核心命令与技能管理 | OpenSkills","sidebarTitle":"掌握核心操作","subtitle":"平台功能: 核心命令与技能管理 | OpenSkills","description":"学习 OpenSkills 平台功能，掌握命令、安装、列出、更新和删除技能等核心操作，理解全局与项目管理的差异。","order":2},"headers":[],"relativePath":"zh/numman-ali/openskills/platforms/index.md","filePath":"zh/numman-ali/openskills/platforms/index.md"}'),s={name:"zh/numman-ali/openskills/platforms/index.md"};function i(o,a,d,n,h,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章节深入讲解 OpenSkills CLI 的核心命令和技能管理功能，帮助你从&quot;会用&quot;到&quot;精通&quot;。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><p>在学习本章节之前，请确保你已完成 <a href="./../start/">快速开始</a> 章节，特别是：</p><ul><li><a href="./../start/installation/">安装 OpenSkills</a>：已成功安装 OpenSkills CLI</li><li><a href="./../start/first-skill/">安装第一个技能</a>：了解基本的技能安装流程</li></ul></div><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><p>本章节包含 6 个主题，覆盖 OpenSkills 的所有核心功能：</p><h3 id="命令详解" tabindex="-1"><a href="./cli-commands/">命令详解</a> <a class="header-anchor" href="#命令详解" aria-label="Permalink to &quot;[命令详解](./cli-commands/)&quot;">​</a></h3><p>完整介绍所有 7 个命令、参数和标志，提供命令速查表。适合需要快速查找命令用法的用户。</p><h3 id="安装来源详解" tabindex="-1"><a href="./install-sources/">安装来源详解</a> <a class="header-anchor" href="#安装来源详解" aria-label="Permalink to &quot;[安装来源详解](./install-sources/)&quot;">​</a></h3><p>详细讲解三种安装来源：GitHub 仓库、本地路径、私有 Git 仓库。每种方式的适用场景、命令格式和注意事项。</p><h3 id="全局安装-vs-项目本地安装" tabindex="-1"><a href="./global-vs-project/">全局安装 vs 项目本地安装</a> <a class="header-anchor" href="#全局安装-vs-项目本地安装" aria-label="Permalink to &quot;[全局安装 vs 项目本地安装](./global-vs-project/)&quot;">​</a></h3><p>解释 <code>--global</code> 和默认（项目本地）安装的区别，帮助你选择合适的安装位置，理解技能搜索优先级规则。</p><h3 id="列出已安装技能" tabindex="-1"><a href="./list-skills/">列出已安装技能</a> <a class="header-anchor" href="#列出已安装技能" aria-label="Permalink to &quot;[列出已安装技能](./list-skills/)&quot;">​</a></h3><p>教会你使用 <code>list</code> 命令查看已安装技能，理解 <code>(project)</code> 和 <code>(global)</code> 位置标签的含义。</p><h3 id="更新技能" tabindex="-1"><a href="./update-skills/">更新技能</a> <a class="header-anchor" href="#更新技能" aria-label="Permalink to &quot;[更新技能](./update-skills/)&quot;">​</a></h3><p>指导你使用 <code>update</code> 命令刷新已安装技能，支持全部更新和指定技能更新，保持技能与源仓库同步。</p><h3 id="删除技能" tabindex="-1"><a href="./remove-skills/">删除技能</a> <a class="header-anchor" href="#删除技能" aria-label="Permalink to &quot;[删除技能](./remove-skills/)&quot;">​</a></h3><p>介绍两种删除方式：交互式 <code>manage</code> 命令和脚本化 <code>remove</code> 命令，帮助你高效管理技能库。</p><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>根据你的需求，选择合适的学习路径：</p><h3 id="路径-a-系统学习-推荐新手" tabindex="-1">路径 A：系统学习（推荐新手） <a class="header-anchor" href="#路径-a-系统学习-推荐新手" aria-label="Permalink to &quot;路径 A：系统学习（推荐新手）&quot;">​</a></h3><p>按顺序学习所有内容，建立完整的知识体系：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>命令详解 → 安装来源 → 全局 vs 项目 → 列出技能 → 更新技能 → 删除技能</span></span></code></pre></div><h3 id="路径-b-按需查阅" tabindex="-1">路径 B：按需查阅 <a class="header-anchor" href="#路径-b-按需查阅" aria-label="Permalink to &quot;路径 B：按需查阅&quot;">​</a></h3><p>根据当前任务直接跳转：</p><table tabindex="0"><thead><tr><th>你想做什么</th><th>阅读这篇</th></tr></thead><tbody><tr><td>查找某个命令的用法</td><td><a href="./cli-commands/">命令详解</a></td></tr><tr><td>从私有仓库安装技能</td><td><a href="./install-sources/">安装来源详解</a></td></tr><tr><td>决定安装到全局还是项目</td><td><a href="./global-vs-project/">全局 vs 项目</a></td></tr><tr><td>查看已安装了哪些技能</td><td><a href="./list-skills/">列出已安装技能</a></td></tr><tr><td>更新技能到最新版本</td><td><a href="./update-skills/">更新技能</a></td></tr><tr><td>清理不用的技能</td><td><a href="./remove-skills/">删除技能</a></td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，你已经掌握了 OpenSkills 的日常使用技能。接下来可以：</p><ul><li><strong><a href="./../advanced/">进阶功能</a></strong>：学习 Universal 模式、自定义输出路径、符号链接、创建自定义技能等高级功能</li><li><strong><a href="./../faq/">常见问题</a></strong>：遇到问题时查阅 FAQ 和故障排除指南</li></ul>',29)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
